# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
{
    var retryCount = 0;
    var maxRetries = 3;
    
    while (retryCount < maxRetries)
    {
        try
        {
            using var context = new EventBookingContext();
            
            // Check available seats with pessimistic locking
            var eventInfo = await context.Events
                .Where(e => e.Id == eventId)
                .Select(e => new { e.TotalSeats, e.AvailableSeats })
                .FirstOrDefaultAsync();
            
            if (eventInfo == null || eventInfo.AvailableSeats < quantity)
                return false;
            
            // Validate purchase quantity
            if (quantity <= 0)
                return false;
            
            // Use transaction with serializable isolation level for concurrency control
            using var transaction = await context.Database.BeginTransactionAsync();
            
            try
            {
                // Re-check availability within transaction
                var updatedEvent = await context.Events
                    .Where(e => e.Id == eventId && e.AvailableSeats >= quantity)
                    .FirstOrDefaultAsync();
                
                if (updatedEvent == null)
                {
                    await transaction.RollbackAsync();
                    return false;
                }
                
                // Update inventory
                updatedEvent.AvailableSeats -= quantity;
                
                // Create purchase record
                var purchase = new Purchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow
                };
                
                context.Purchases.Add(purchase);
                
                await context.SaveChangesAsync();
                await transaction.CommitAsync();
                
                return true;
            }
            catch
            {
                await transaction.RollbackAsync();
                throw;
            }
        }
        catch (Exception)
        {
            retryCount++;
            if (retryCount >= maxRetries) throw;
            
            // Brief delay before retry
            await Task.Delay(100 * retryCount);
        }
    }
    
    return false;
}